{
  "family": "Fries-, Photo-Fries, and Anionic Ortho-Fries Rearrangement",
  "candidate": {
    "substrate_smiles": [
      "CC(=O)Oc1ccccc1"
    ],
    "product_smiles": [
      "CC(=O)c1ccccc1O"
    ],
    "optional_reagent_smiles": [
      "Cl[Al](Cl)Cl"
    ],
    "rationale": "The Fries rearrangement of phenyl acetate to 2-hydroxyacetophenone is the simplest and most frequently cited textbook example. It clearly demonstrates the core transformation: the migration of an acyl group from a phenolic oxygen to an ortho position on the aromatic ring, catalyzed by a Lewis acid (AlCl3). This example is minimal, acyclic in its key functional groups, and avoids complex substituents, making it an ideal canonical representation.",
    "collision_avoidance_note": "This example uses a simple phenyl acetate substrate to avoid overlap with more complex aromatic substitution reactions. The transformation is a specific intramolecular rearrangement of an ester to a ketone, which is distinct from intermolecular Friedel-Crafts acylation, Claisen rearrangement (which involves allyl ethers), or other electrophilic aromatic substitutions. The acyl group is small (acetyl) to prevent confusion with reactions involving larger, more reactive groups."
  }
}
